    pub fn handle_message(&self, mut client: Value, mut message: Value) {
        //
        // ping
        //    {
        //        "id": 1587523073344,
        //        "method": "public/heartbeat",
        //        "code": 0
        //    }
        // auth
        //     { id: 1648132625434, method: "public/auth", code: 0 }
        // ohlcv
        //    {
        //        "code": 0,
        //        "method": "subscribe",
        //        "result": {
        //          "instrument_name": "BTC_USDT",
        //          "subscription": "candlestick.1m.BTC_USDT",
        //          "channel": "candlestick",
        //          "depth": 300,
        //          "interval": "1m",
        //          "data": [ [Object] ]
        //        }
        //      }
        // ticker
        //    {
        //        "info":{
        //           "instrument_name":"BTC_USDT",
        //           "subscription":"ticker.BTC_USDT",
        //           "channel":"ticker",
        //           "data":[ { } ]
        //
        // handle unsubscribe
        // {"id":1725448572836,"method":"unsubscribe","code":0}
        //
        if is_true(&self.handle_error_message(client.clone(), message.clone())) {
            return;
        }
        let mut method: Value = self.safe_string_k(message.clone(), "method", &[]);
        let mut methods: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("".to_string(), Value::Null.clone());
                m.insert("public/heartbeat".to_string(), Value::Null.clone());
                m.insert("public/auth".to_string(), Value::Null.clone());
                m.insert("private/create-order".to_string(), Value::Null.clone());
                m.insert("private/amend-order".to_string(), Value::Null.clone());
                m.insert("private/cancel-order".to_string(), Value::Null.clone());
                m.insert("private/cancel-all-orders".to_string(), Value::Null.clone());
                m.insert("private/close-position".to_string(), Value::Null.clone());
                m.insert("subscribe".to_string(), Value::Null.clone());
                m.insert("unsubscribe".to_string(), Value::Null.clone());
            m
        });
        let mut callMethod: Value = self.safe_value(methods.clone(), method.clone(), &[]);
        if !is_equal(&callMethod, &Value::Null) {
            callMethod.call(&[client.clone(), message.clone()]);
        }
}

